#include <bits/stdc++.h>
using namespace std;

int n, q;
bool c[100005];
vector<int> s[100005];
bool t[100005];

void DFS(int k, bool r) {
    // printf(">>> k: %d,  r: %d,  t: %d,  c: %d\n", k, r, t[k], c[k]);
    if (r ^ t[k]) c[k] = !c[k];
    for (int i : s[k]) {
        // printf("  -> k: %d,  r: %d\n", i, r ^ t[k]);
        DFS(i, r ^ t[k]);
    }
}

int main() {
    cin >> n;
    for (int i = 2; i <= n; i++) {
        int x;
        cin >> x;
        s[x].push_back(i);
    }
    getchar();
    for (int i = 1; i <= n; i++) {
        char ch = getchar();
        c[i] = ch - '0';
    }
    cin >> q;
    for (int i = 0; i < q; i++) {
        int a;
        cin >> a;
        t[a] = !t[a];
    }
    DFS(1, false);
    for (int i = 1; i <= n; i++) {
        cout << c[i];
    }
    return 0;
}
